import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter details.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard'); 
    } catch (err) { 
      toast.error('Could not log in.'); 
    } 
    finally { setLoading(false); }
  };

  return (
    <div className="min-h-[85vh] w-full flex flex-col items-center justify-center p-6">
      {/* Login Card with CSS Variables */}
      <div className="w-full max-w-md vault-card">
        <h2 className="text-3xl font-bold text-center mb-2" style={{ color: 'var(--accent-primary)' }}>
          Finify
        </h2>
        <p className="text-center mb-8" style={{ color: 'var(--text-muted)' }}>
          Sign in to your account
        </p>
        
        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-xs font-semibold uppercase tracking-wider mb-2" style={{ color: 'var(--text-secondary)' }}>
              Email
            </label>
            <input 
                type="email" 
                placeholder="you@example.com" 
                value={email} 
                onChange={(e) => setEmail(e.target.value)} 
                className="cyber-input"
                style={{ 
                  backgroundColor: 'var(--input-bg)',
                  borderColor: 'var(--input-border)',
                  color: 'var(--text-primary)'
                }}
            />
          </div>
          
          <div className="relative">
            <label className="block text-xs font-semibold uppercase tracking-wider mb-2" style={{ color: 'var(--text-secondary)' }}>
              Password
            </label>
            <input 
                type={showPass ? "text" : "password"} 
                placeholder="Enter your password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="cyber-input pr-12"
                style={{ 
                  backgroundColor: 'var(--input-bg)',
                  borderColor: 'var(--input-border)',
                  color: 'var(--text-primary)'
                }}
            />
            <button 
              type="button" 
              onClick={() => setShowPass(!showPass)} 
              className="absolute right-4 top-[42px] cursor-pointer"
              style={{ color: 'var(--text-muted)' }}
            >
              {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
          
          <button 
            type="submit" 
            className="cyber-btn"
            style={{ 
              backgroundImage: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))' 
            }}
            disabled={loading}
          >
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>
        
        <div className="text-center mt-6">
            <Link to="/register" style={{ color: 'var(--accent-primary)' }}>
              Don't have an account? Sign up
            </Link>
        </div>
      </div>
    </div>
  );
};
export default LoginPage;
